import React, { useState, useEffect, useContext } from 'react';
import { db} from '../firebase/config';
import {
  collection, addDoc, updateDoc, deleteDoc,
  doc, onSnapshot, serverTimestamp, orderBy, query
} from 'firebase/firestore';
import { ref, uploadBytesResumable, getDownloadURL } from 'firebase/storage';
import { Plus, Pencil, Trash2, Upload, X } from 'lucide-react';
import { ToastContext } from '../App';
import './ProductManager.css';

const SECTIONS  = ['bestSellers', 'newArrivals'];
const CATS      = ['rings','necklaces','earrings','bracelets','watches','pendants','anklets','charms'];
const EMPTY     = { name:'', price:'', category:'rings', section:'bestSellers', image:'' };

export default function ProductManager() {
  const { showToast } = useContext(ToastContext);
  const [products, setProducts]   = useState([]);
  const [form,     setForm]       = useState(EMPTY);
  const [editId,   setEditId]     = useState(null);
  const [showForm, setShowForm]   = useState(false);
  const [uploading,setUploading]  = useState(false);
  const [progress, setProgress]   = useState(0);
  const [filter,   setFilter]     = useState('all');

  useEffect(() => {
    const q = query(collection(db, 'products'), orderBy('createdAt','desc'));
    const unsub = onSnapshot(q, snap =>
      setProducts(snap.docs.map(d => ({ id: d.id, ...d.data() })))
    );
    return () => unsub();
  }, []);

  /* ── image upload ── */
  const handleImageUpload = (file) => {
    if (!file) return;
    const storageRef = ref(storage, `products/${Date.now()}_${file.name}`);
    const task = uploadBytesResumable(storageRef, file);
    setUploading(true);
    task.on('state_changed',
      snap => setProgress(Math.round(snap.bytesTransferred / snap.totalBytes * 100)),
      () => { showToast('Upload failed', 'error'); setUploading(false); },
      async () => {
        const url = await getDownloadURL(task.snapshot.ref);
        setForm(f => ({ ...f, image: url }));
        setUploading(false);
        setProgress(0);
        showToast('Image uploaded!');
      }
    );
  };

  /* ── save (add or update) ── */
  const handleSave = async () => {
    if (!form.name || !form.price) return showToast('Name and price are required', 'error');
    try {
      const data = { ...form, price: Number(form.price) };
      if (editId) {
        await updateDoc(doc(db, 'products', editId), data);
        showToast('Product updated!');
      } else {
        await addDoc(collection(db, 'products'), { ...data, createdAt: serverTimestamp() });
        showToast('Product added! It is now live on client site.');
      }
      setForm(EMPTY); setEditId(null); setShowForm(false);
    } catch { showToast('Error saving product', 'error'); }
  };

  /* ── delete ── */
  const handleDelete = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    await deleteDoc(doc(db, 'products', id));
    showToast('Product deleted.');
  };

  /* ── edit ── */
  const handleEdit = (p) => {
    setForm({ name: p.name, price: p.price, category: p.category, section: p.section, image: p.image || '' });
    setEditId(p.id);
    setShowForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const filtered = filter === 'all' ? products : products.filter(p => p.section === filter);

  return (
    <div className="product-manager">
      <div className="page-header">
        <div>
          <h1 className="page-title">Products</h1>
          <p className="page-sub">Add, edit, or remove products. Changes go live on client instantly.</p>
        </div>
        <button className="btn-primary" onClick={() => { setForm(EMPTY); setEditId(null); setShowForm(s => !s); }}>
          {showForm ? <><X size={15}/> Cancel</> : <><Plus size={15}/> Add Product</>}
        </button>
      </div>

      {/* ── FORM ── */}
      {showForm && (
        <div className="card product-form">
          <h3 className="form-title">{editId ? 'Edit Product' : 'Add New Product'}</h3>
          <div className="form-grid">
            <div className="form-field">
              <label className="field-label">Product Name</label>
              <input className="field-input" value={form.name}
                onChange={e => setForm(f => ({...f, name: e.target.value}))}
                placeholder="e.g. Gold Signet Ring" />
            </div>
            <div className="form-field">
              <label className="field-label">Price (USD)</label>
              <input className="field-input" type="number" value={form.price}
                onChange={e => setForm(f => ({...f, price: e.target.value}))}
                placeholder="e.g. 890" />
            </div>
            <div className="form-field">
              <label className="field-label">Category</label>
              <select className="field-input" value={form.category}
                onChange={e => setForm(f => ({...f, category: e.target.value}))}>
                {CATS.map(c => <option key={c} value={c}>{c.charAt(0).toUpperCase()+c.slice(1)}</option>)}
              </select>
            </div>
            <div className="form-field">
              <label className="field-label">Section</label>
              <select className="field-input" value={form.section}
                onChange={e => setForm(f => ({...f, section: e.target.value}))}>
                {SECTIONS.map(s => <option key={s} value={s}>{s === 'bestSellers' ? 'Best Sellers' : 'New Arrivals'}</option>)}
              </select>
            </div>
          </div>

          {/* Image upload */}
          <div className="form-field" style={{marginTop:16}}>
            <label className="field-label">Product Image</label>
            <div className="upload-area">
              {form.image
                ? <div className="upload-preview">
                    <img src={form.image} alt="preview" />
                    <button className="remove-img" onClick={() => setForm(f=>({...f,image:''}))}>
                      <X size={14}/> Remove
                    </button>
                  </div>
                : <label className="upload-box">
                    <input type="file" accept="image/*" style={{display:'none'}}
                      onChange={e => handleImageUpload(e.target.files[0])} />
                    <Upload size={24} color="#bbb" />
                    <p>Click to upload image</p>
                    <span>JPG, PNG, WEBP up to 10MB</span>
                  </label>
              }
              {uploading && (
                <div className="upload-progress">
                  <div className="progress-bar" style={{width:`${progress}%`}} />
                  <span>{progress}%</span>
                </div>
              )}
            </div>
            {/* OR paste URL */}
            <input className="field-input" style={{marginTop:10}} value={form.image}
              onChange={e => setForm(f=>({...f, image:e.target.value}))}
              placeholder="Or paste image URL directly..." />
          </div>

          <div className="form-actions">
            <button className="btn-primary" onClick={handleSave} disabled={uploading}>
              {editId ? 'Save Changes' : 'Add Product'}
            </button>
            <button className="btn-secondary" onClick={() => { setShowForm(false); setEditId(null); setForm(EMPTY); }}>
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* ── FILTER TABS ── */}
      <div className="filter-tabs">
        {[['all','All'], ['bestSellers','Best Sellers'], ['newArrivals','New Arrivals']].map(([val,label]) => (
          <button key={val}
            className={`filter-tab ${filter===val?'active':''}`}
            onClick={() => setFilter(val)}>
            {label} {val==='all' ? `(${products.length})` : `(${products.filter(p=>p.section===val).length})`}
          </button>
        ))}
      </div>

      {/* ── PRODUCTS TABLE ── */}
      <div className="card" style={{padding:0, overflow:'hidden'}}>
        {filtered.length === 0
          ? <p style={{padding:'32px', color:'#aaa', textAlign:'center', fontStyle:'italic'}}>
              No products yet. Click "Add Product" to get started.
            </p>
          : <table className="product-table">
              <thead>
                <tr>
                  <th>Image</th>
                  <th>Name</th>
                  <th>Category</th>
                  <th>Section</th>
                  <th>Price</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(p => (
                  <tr key={p.id}>
                    <td>
                      <div className="product-thumb">
                        {p.image
                          ? <img src={p.image} alt={p.name} />
                          : <div className="thumb-placeholder">?</div>
                        }
                      </div>
                    </td>
                    <td className="product-name-cell">{p.name}</td>
                    <td><span className="badge badge-gray">{p.category}</span></td>
                    <td><span className={`badge ${p.section==='bestSellers'?'badge-gold':'badge-green'}`}>
                      {p.section==='bestSellers'?'Best Sellers':'New Arrivals'}
                    </span></td>
                    <td className="price-cell">${(p.price||0).toLocaleString()}</td>
                    <td>
                      <div className="action-btns">
                        <button className="action-btn edit" onClick={() => handleEdit(p)} title="Edit">
                          <Pencil size={14}/>
                        </button>
                        <button className="action-btn delete" onClick={() => handleDelete(p.id)} title="Delete">
                          <Trash2 size={14}/>
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
        }
      </div>
    </div>
  );
}
